use sha256::sha256_var;
use poseidon::poseidon2::Poseidon2;

fn main(
    raw_msg: [u8; 700],
    dg_len: u32,
    field_offsets: [u32; 32],
    field_lengths: [u32; 32],
    salt: pub Field,
) -> pub [Field; 3] {
    let hash = sha256_var(raw_msg, dg_len);

    // Immutable: cccdNumber(0), dateOfBirth(2), ethnicity(5), placeOfOrigin(7), parentsInfo(12)
    let immutable_indices: [u32; 5] = [0, 2, 5, 7, 12];

    let mut immutable_packed: [Field; 20] = [0; 20];

    for idx in 0..5 {
        let fi = immutable_indices[idx];

        let offset = field_offsets[fi];

        let length = field_lengths[fi];

        for f in 0..4 {
            let mut felt: Field = 0;

            for b in 0..31 {
                let byte_idx: u32 = f * 31 + b;

                if byte_idx < length {
                    felt = felt * 256 + raw_msg[offset + byte_idx] as Field;
                }
            }

            immutable_packed[idx * 4 + f] = felt;
        }
    }

    let packed_hash = Poseidon2::hash(immutable_packed, 20);

    let mut leaves: [Field; 32] = [0; 32];

    for i in 0..32 {
        let offset = field_offsets[i];

        let length = field_lengths[i];

        let tag_id: u8 = (i as u8) + 1;

        assert(offset >= 7);

        assert(offset + length <= 700);

        assert(raw_msg[offset - 7] == 0x30);

        assert(raw_msg[offset - 5] == 0x02);

        assert(raw_msg[offset - 4] == 0x01);

        assert(raw_msg[offset - 3] == tag_id);

        let mut packed: [Field; 8] = [0; 8];

        packed[0] = tag_id as Field;

        packed[1] = length as Field;

        for f in 0..4 {
            let mut felt: Field = 0;

            for b in 0..31 {
                let byte_idx: u32 = f * 31 + b;

                if byte_idx < length {
                    felt = felt * 256 + raw_msg[offset + byte_idx] as Field;
                }
            }

            packed[2 + f] = felt;
        }

        packed[6] = salt;

        packed[7] = packed_hash;

        leaves[i] = Poseidon2::hash(packed, 8);
    }

    let mut level_16: [Field; 16] = [0; 16];

    for i in 0..16 {
        level_16[i] = Poseidon2::hash([leaves[2 * i], leaves[2 * i + 1]], 2);
    }

    let mut level_8: [Field; 8] = [0; 8];

    for i in 0..8 {
        level_8[i] = Poseidon2::hash([level_16[2 * i], level_16[2 * i + 1]], 2);
    }

    let mut level_4: [Field; 4] = [0; 4];

    for i in 0..4 {
        level_4[i] = Poseidon2::hash([level_8[2 * i], level_8[2 * i + 1]], 2);
    }

    let mut level_2: [Field; 2] = [0; 2];

    for i in 0..2 {
        level_2[i] = Poseidon2::hash([level_4[2 * i], level_4[2 * i + 1]], 2);
    }

    let root = Poseidon2::hash([level_2[0], level_2[1]], 2);

    let mut hash_hi: Field = 0;

    for i in 0..16 {
        hash_hi = hash_hi * 256 + hash[i] as Field;
    }

    let mut hash_lo: Field = 0;

    for i in 16..32 {
        hash_lo = hash_lo * 256 + hash[i] as Field;
    }

    let binding = Poseidon2::hash([hash_hi, hash_lo, salt], 3);

    let identity = Poseidon2::hash([packed_hash, salt], 2);

    let commitment = Poseidon2::hash([root, salt], 2);

    [binding, identity, commitment]
}

